146→initTheme();
147→injectMarkdownStyles();
148→initHighlighter();
149→initPWA();
150→initMobile();
151→const i18nReady = initI18n()
152→	.then(() => {
153→		translateStaticElements(document.documentElement);
154→	})
155→	.catch((err: unknown) => {
156→		console.warn("[i18n] failed to initialize", err);
157→	});
158→let appStarted = false;
159→
160→function startAppAfterI18n(): void {
161→	if (appStarted) return;
162→	appStarted = true;
163→	i18nReady.finally(() => {
164→		startApp();
165→	});
