242→function applyMemory(mem: MemInfo | null): void {
243→	if (!mem) return;
244→	const el = document.getElementById("memoryInfo");
245→	if (!el) return;
246→	const fmt = (b: number): string => prettyBytes(b, { maximumFractionDigits: 0, space: false });
247→	let localLlamaCpp = 0;
248→	if (typeof mem.localLlamaCpp === "number") {
249→		localLlamaCpp = mem.localLlamaCpp;
250→	} else if (typeof mem.local_llama_cpp === "number") {
251→		// Backward compatibility with older payload casing.
252→		localLlamaCpp = mem.local_llama_cpp;
253→	}
254→	const localLlamaPart = localLlamaCpp > 0 ? ` (llama.cpp ${fmt(localLlamaCpp)})` : "";
255→	el.textContent = `${fmt(mem.process)}${localLlamaPart} \u00b7 ${fmt(mem.available)} free / ${fmt(mem.total)}`;
256→}
257→
258→applyMemory(gon.get("mem") as MemInfo | null);
259→gon.onChange("mem", applyMemory as (v: unknown) => void);
260→onEvent("tick", (_payload: unknown) => {
261→	const payload = _payload as Record<string, unknown>;
262→	applyMemory(payload.mem as MemInfo | null);
263→});
