346→function updateAuthChrome(auth: AuthStatus | null): void {
347→	const showLogout = !!(auth?.authenticated && !auth.auth_disabled && (auth.has_password || auth.has_passkeys));
348→	if (logoutBtn) {
349→		logoutBtn.style.display = showLogout ? "" : "none";
350→	}
351→	if (mobileMenuLogoutBtn) {
352→		mobileMenuLogoutBtn.style.display = showLogout ? "" : "none";
353→	}
354→	if (mobileMenuPanel) {
355→		mobileMenuPanel.classList.toggle("logout-hidden", !showLogout);
356→	}
357→	if (!showLogout) {
358→		closeMobileMenu();
359→	}
360→
361→	const banner = document.getElementById("authDisabledBanner");
362→	if (banner) {
363→		const showAuthDisabled = !!(auth?.auth_disabled && !auth.localhost_only);
364→		banner.style.display = showAuthDisabled ? "" : "none";
365→	}
366→}
367→
368→function refreshAuthChrome(): Promise<AuthStatus | null> {
369→	return fetch("/api/auth/status")
370→		.then((r) => (r.ok ? r.json() : null))
371→		.then((auth: AuthStatus | null) => {
372→			updateAuthChrome(auth);
373→			return auth;
374→		})
375→		.catch(() => null);
376→}
377→
378→window.addEventListener("moltis:auth-status-changed", () => {
379→	refreshAuthChrome()
380→		.then((auth) => {
381→			if (!auth) return;
382→			if (auth.setup_required) {
383→				clearSensitiveData();
384→				window.location.assign("/onboarding");
385→				return;
386→			}
387→			if (!auth.authenticated) {
388→				clearSensitiveData();
389→				window.location.assign("/login");
390→			}
391→		})
392→		.finally(() => {
393→			window.dispatchEvent(new CustomEvent("moltis:auth-status-sync-complete"));
394→		});
395→});
396→
397→/**
398→ * Purge cached sensitive data so that a logged-out page cannot display
399→ * session previews, identity info, or other user-scoped state.
400→ */
401→function clearSensitiveData(): void {
402→	// Clear session store and legacy state
403→	sessionStore.setAll([]);
404→	S.setSessions([]);
405→	renderSessionList();
406→
407→	// Clear model and project stores
408→	modelStore.setAll([]);
409→	S.setModels([]);
410→	projectStore.setAll([]);
411→	S.setProjects([]);
412→
413→	// Clear identity from gon so sidebar/header no longer shows it
414→	gon.set("identity", null);
415→	gon.set("sessions_recent", null);
416→	// Signal vault sealed so SessionList shows the correct placeholder
417→	gon.set("vault_status", "sealed");
418→}
419→
420→// Seed sandbox info from gon so the settings page can render immediately
421→// without waiting for the auth-protected /api/bootstrap fetch.
422→try {
423→	const gonSandbox = gon.get("sandbox");
424→	if (gonSandbox) S.setSandboxInfo(gonSandbox);
425→} catch (_) {
426→	// Non-fatal — sandbox info will arrive via bootstrap.
427→}
428→// Check auth status before mounting the app.
429→fetch("/api/auth/status")
430→	.then((r) => (r.ok ? r.json() : null))
431→	.then((auth: AuthStatus | null) => {
432→		if (!auth) {
433→			// Auth endpoints not available — no auth configured, proceed normally.
434→			startAppAfterI18n();
435→			return;
436→		}
437→		if (auth.setup_required) {
438→			window.location.assign("/onboarding");
439→			return;
440→		}
441→		if (!auth.authenticated) {
442→			// Server-side middleware handles the redirect to /login.
443→			// This is a defense-in-depth fallback for edge cases
444→			// (e.g. session expired after the page was already served).
445→			window.location.assign("/login");
446→			return;
447→		}
448→		updateAuthChrome(auth);
449→		startAppAfterI18n();
450→	})
451→	.catch(() => {
452→		// If auth check fails, proceed anyway (backward compat).
453→		startAppAfterI18n();
454→	});
