456→function showUpdateBanner(update: { available?: boolean; latest_version?: string; release_url?: string } | null): void {
457→	const el = document.getElementById("updateBanner");
458→	if (!el) return;
459→
460→	const latestVersion = update?.latest_version || null;
461→	currentUpdateVersion = latestVersion;
462→	const dismissedVersion = localStorage.getItem(UPDATE_DISMISS_KEY);
463→
464→	if (update?.available && (!latestVersion || dismissedVersion !== latestVersion)) {
465→		const versionEl = document.getElementById("updateLatestVersion");
466→		if (versionEl) {
467→			versionEl.textContent = latestVersion ? `v${latestVersion}` : "";
468→		}
469→		const linkEl = S.$<HTMLAnchorElement>("updateReleaseLink");
470→		if (linkEl && update.release_url) {
471→			linkEl.href = update.release_url;
472→		}
473→		el.style.display = "";
474→	} else {
475→		el.style.display = "none";
476→	}
477→}
478→
479→function initUpdateBannerDismiss(): void {
480→	const dismissBtn = S.$("updateDismissBtn");
481→	if (!dismissBtn || dismissBtn.dataset.bound === "1") return;
482→	dismissBtn.dataset.bound = "1";
483→	dismissBtn.addEventListener("click", () => {
484→		if (currentUpdateVersion) {
485→			localStorage.setItem(UPDATE_DISMISS_KEY, currentUpdateVersion);
486→		}
487→		const el = document.getElementById("updateBanner");
488→		if (el) el.style.display = "none";
489→	});
490→}
491→
492→function showVaultBanner(status: string | null): void {
493→	const el = document.getElementById("vaultBanner");
494→	if (!el) return;
495→	el.style.display = status === "sealed" ? "" : "none";
496→}
497→
498→function showBranchBanner(branch: string | null): void {
499→	const el = document.getElementById("branchBanner");
500→	if (!el) return;
501→
502→	if (branch) {
503→		const branchNameEl = document.getElementById("branchName");
504→		if (branchNameEl) branchNameEl.textContent = branch;
505→		el.style.display = "";
506→
507→		// Prefix page title with branch name.
508→		document.title = `[${branch}] ${formatPageTitle(gon.get("identity") as IdentityInfo | null)}`;
509→	} else {
510→		el.style.display = "none";
511→
512→		// Restore original title
513→		document.title = formatPageTitle(gon.get("identity") as IdentityInfo | null);
514→	}
515→}
516→
517→function applyIdentity(identity: IdentityInfo | null): void {
518→	const emojiEl = document.getElementById("titleEmoji");
519→	const nameEl = document.getElementById("titleName");
520→	if (emojiEl) emojiEl.textContent = identity?.emoji ? `${identity.emoji} ` : "";
521→	if (nameEl) nameEl.textContent = identity?.name || "moltis";
522→	applyIdentityFavicon(identity);
523→	const branch = gon.get("git_branch") as string | null;
524→
525→	// Keep page title in sync with identity and branch.
526→	const title = formatPageTitle(identity);
527→	if (branch) {
528→		document.title = `[${branch}] ${title}`;
529→	} else {
530→		document.title = title;
531→	}
532→}
533→
534→function applyModels(models: ModelEntry[]): void {
535→	const arr = models || [];
536→	modelStore.setAll(arr as never[]);
537→	// Dual-write to state.js for backward compat
538→	S.setModels(arr);
539→	if (arr.length === 0) return;
540→	const saved = localStorage.getItem("moltis-model") || "";
541→	const found = arr.find((m) => m.id === saved);
542→	if (found) {
543→		modelStore.select(found.id);
544→		S.setSelectedModelId(found.id);
545→	} else {
546→		modelStore.select(arr[0].id);
547→		S.setSelectedModelId(arr[0].id);
548→		localStorage.setItem("moltis-model", modelStore.selectedModelId.value);
549→	}
550→}
551→
552→function fetchBootstrap(): void {
553→	// Fetch bootstrap data asynchronously — populates sidebar, models, projects
554→	// as soon as the data arrives, without blocking the initial page render.
555→	fetch("/api/bootstrap?include_sessions=false")
556→		.then((r) => {
557→			if (r.status === 401 || r.status === 403) {
558→				window.dispatchEvent(new CustomEvent("moltis:auth-status-changed"));
559→				return Promise.reject(new Error("auth"));
560→			}
561→			return r.json();
562→		})
563→		.then((boot: BootstrapData) => {
564→			if (boot.channels)
565→				S.setCachedChannels((boot.channels as { channels?: unknown[] }).channels || boot.channels || []);
566→			if (boot.sessions) {
567→				const bootSessions = boot.sessions || [];
568→				sessionStore.setAll(bootSessions as never[]);
569→				// Dual-write to state.js for backward compat
570→				S.setSessions(bootSessions);
571→				renderSessionList();
572→			} else {
573→				// Keep full list fetch separate from bootstrap payload size.
574→				fetchSessions();
575→			}
576→			if (boot.models) applyModels(boot.models);
577→			refreshWelcomeCardIfNeeded();
578→			if (boot.projects) {
579→				const bootProjects = boot.projects || [];
580→				projectStore.setAll(bootProjects as never[]);
581→				// Dual-write to state.js for backward compat
582→				S.setProjects(bootProjects);
583→				renderProjectSelect();
584→				renderSessionProjectSelect();
585→			}
586→			S.setSandboxInfo(boot.sandbox || null);
587→			// Re-apply sandbox UI now that we know the backend status.
588→			// This fixes the race where the chat page renders before bootstrap completes.
589→			updateSandboxUI(S.sessionSandboxEnabled);
590→			updateSandboxImageUI(S.sessionSandboxImage);
591→			if (boot.counts) updateNavCounts(boot.counts);
592→		})
593→		.catch(() => {
594→			// If bootstrap fails, hydrate from dedicated lightweight endpoints.
595→			fetchSessions();
596→			fetchModels();
597→			fetchProjects();
598→		});
599→}
