286→    fn parameters_schema(&self) -> Value {
287→        json!({
288→            "type": "object",
289→            "required": ["name"],
290→            "properties": {
291→                "name": {
292→                    "type": "string",
293→                    "description": "Skill name to delete"
294→                }
