 991→    data_dir: PathBuf,
 992→    checkpoints: CheckpointManager,
 993→}
 994→
 995→impl PatchSkillTool {
 996→    pub fn new(data_dir: PathBuf) -> Self {
 997→        let checkpoints = CheckpointManager::new(data_dir.clone());
 998→        Self {
 999→            data_dir,
1000→            checkpoints,
1001→        }
1002→    }
1003→
1004→    fn skills_dir(&self) -> PathBuf {
1005→        self.data_dir.join("skills")
1006→    }
1007→}
1008→
1009→/// Maximum number of patches per call.
1010→const MAX_PATCHES_PER_CALL: usize = 10;
1011→
1012→#[async_trait]
1013→impl AgentTool for PatchSkillTool {
1014→    fn name(&self) -> &str {
1015→        "patch_skill"
1016→    }
1017→
1018→    fn description(&self) -> &str {
1019→        "Apply surgical find/replace patches to an existing personal skill's SKILL.md. \
1020→         More efficient than update_skill when fixing a few lines — avoids regenerating \
1021→         the entire body."
1022→    }
1023→
1024→    fn parameters_schema(&self) -> Value {
1025→        json!({
1026→            "type": "object",
1027→            "required": ["name", "patches"],
1028→            "properties": {
1029→                "name": {
1030→                    "type": "string",
1031→                    "description": "Skill name to patch"
1032→                },
1033→                "patches": {
1034→                    "type": "array",
1035→                    "description": "Ordered list of find/replace operations applied sequentially",
1036→                    "minItems": 1,
1037→                    "maxItems": MAX_PATCHES_PER_CALL,
1038→                    "items": {
1039→                        "type": "object",
1040→                        "required": ["find", "replace"],
1041→                        "properties": {
1042→                            "find": {
1043→                                "type": "string",
1044→                                "description": "Exact string to find in the skill body"
1045→                            },
1046→                            "replace": {
1047→                                "type": "string",
1048→                                "description": "Replacement string"
1049→                            }
1050→                        }
1051→                    }
1052→                },
1053→                "description": {
1054→                    "type": "string",
1055→                    "description": "Optional: update the frontmatter description"
1056→                }
1057→            }
1058→        })
1059→    }
1060→
1061→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
1062→        let name = params
1063→            .get("name")
1064→            .and_then(|v| v.as_str())
1065→            .ok_or_else(|| Error::message("missing 'name'"))?;
1066→        let patches = params
1067→            .get("patches")
1068→            .and_then(|v| v.as_array())
1069→            .ok_or_else(|| Error::message("missing 'patches'"))?;
1070→        let new_description = params.get("description").and_then(|v| v.as_str());
1071→
1072→        if !moltis_skills::parse::validate_name(name) {
1073→            return Err(Error::message(format!(
1074→                "invalid skill name '{name}': must be 1-64 lowercase alphanumeric/hyphen chars"
1075→            ))
1076→            .into());
1077→        }
1078→        if patches.is_empty() {
1079→            return Err(Error::message("at least one patch is required").into());
1080→        }
1081→        if patches.len() > MAX_PATCHES_PER_CALL {
1082→            return Err(Error::message(format!(
1083→                "too many patches: maximum is {MAX_PATCHES_PER_CALL}"
1084→            ))
1085→            .into());
1086→        }
1087→
1088→        let skill_dir = self.skills_dir().join(name);
1089→        if !skill_dir.exists() {
1090→            return Err(Error::message(format!(
1091→                "skill '{name}' does not exist; use create_skill first"
1092→            ))
1093→            .into());
1094→        }
1095→
1096→        // Reject symlinked skill directories (same check as DeleteSkillTool).
1097→        let canonical_base = self
1098→            .skills_dir()
1099→            .canonicalize()
1100→            .unwrap_or_else(|_| self.skills_dir().clone());
1101→        let canonical_target = skill_dir
1102→            .canonicalize()
1103→            .unwrap_or_else(|_| skill_dir.clone());
1104→        if !canonical_target.starts_with(&canonical_base) {
1105→            return Err(Error::message("can only patch personal skills").into());
1106→        }
1107→        match tokio::fs::symlink_metadata(&skill_dir).await {
1108→            Ok(meta) if meta.file_type().is_symlink() => {
1109→                return Err(Error::message(format!(
1110→                    "skill '{name}' directory must not be a symlink"
1111→                ))
1112→                .into());
1113→            },
1114→            Ok(_) => {},
1115→            Err(e) => {
1116→                return Err(
1117→                    Error::message(format!("skill '{name}' path not accessible: {e}")).into(),
1118→                );
1119→            },
1120→        }
1121→
1122→        let skill_md_path = skill_dir.join("SKILL.md");
1123→        let raw = tokio::fs::read_to_string(&skill_md_path)
1124→            .await
1125→            .map_err(|e| Error::message(format!("failed to read skill '{name}': {e}")))?;
1126→
1127→        // Parse frontmatter + body.
1128→        let (frontmatter_block, body) = split_frontmatter_body(&raw);
1129→
1130→        // Apply patches sequentially to the body.
1131→        let mut patched_body = body.to_string();
1132→        let mut applied = 0usize;
1133→        for (i, patch) in patches.iter().enumerate() {
1134→            let find = patch
1135→                .get("find")
1136→                .and_then(|v| v.as_str())
1137→                .ok_or_else(|| Error::message(format!("patch[{i}]: missing 'find'")))?;
1138→            let replace = patch
1139→                .get("replace")
1140→                .and_then(|v| v.as_str())
1141→                .ok_or_else(|| Error::message(format!("patch[{i}]: missing 'replace'")))?;
1142→
1143→            if find.is_empty() {
1144→                return Err(Error::message(format!("patch[{i}]: 'find' must not be empty")).into());
1145→            }
1146→            if !patched_body.contains(find) {
1147→                return Err(Error::message(format!(
1148→                    "patch[{i}]: string not found in skill body: {find:?}"
1149→                ))
1150→                .into());
1151→            }
1152→
1153→            patched_body = patched_body.replacen(find, replace, 1);
1154→            applied += 1;
1155→        }
1156→
1157→        // Optionally update the frontmatter description.
1158→        let final_content = if let Some(desc) = new_description {
1159→            let updated_fm = update_frontmatter_description(frontmatter_block, desc);
1160→            format!("{updated_fm}{patched_body}")
1161→        } else {
1162→            format!("{frontmatter_block}{patched_body}")
1163→        };
1164→
1165→        // Ensure trailing newline.
1166→        let final_content = if final_content.ends_with('\n') {
1167→            final_content
1168→        } else {
1169→            format!("{final_content}\n")
1170→        };
1171→
1172→        let checkpoint = self
1173→            .checkpoints
1174→            .checkpoint_path(&skill_dir, "patch_skill")
1175→            .await?;
1176→
1177→        tokio::fs::write(&skill_md_path, &final_content).await?;
1178→
1179→        // Run injection scan on the result.
1180→        let hits = moltis_skills::safety::scan_skill_body(name, &patched_body);
1181→        let warning = if !hits.is_empty() {
1182→            tracing::warn!(
1183→                skill = %name,
1184→                patterns = ?hits,
1185→                "patched skill body contains potential prompt-injection patterns"
1186→            );
1187→            Some(format!(
1188→                "Warning: patched body matches injection patterns: {}",
1189→                hits.join(", ")
1190→            ))
1191→        } else {
1192→            None
1193→        };
1194→
1195→        let mut response = json!({
1196→            "patched": true,
1197→            "patches_applied": applied,
1198→            "checkpointId": checkpoint.id,
1199→        });

1200→        if let Some(warn_msg) = warning
1201→            && let Some(m) = response.as_object_mut()
1202→        {
1203→            m.insert("warning".into(), json!(warn_msg));
1204→        }
1205→
1206→        Ok(response)
1207→    }
1208→}
