1210→/// Split a SKILL.md file into its frontmatter block (including delimiters and
1211→/// trailing newline) and the body. If there is no frontmatter, frontmatter_block
1212→/// is empty.
1213→fn split_frontmatter_body(raw: &str) -> (&str, &str) {
1214→    if !raw.starts_with("---") {
1215→        return ("", raw);
1216→    }
1217→    // Find the closing `---` after the opening one.
1218→    if let Some(end_idx) = raw[3..].find("\n---") {
1219→        // end_idx is relative to raw[3..], so the closing `---` starts at 3 + end_idx + 1
1220→        let closing_end = 3 + end_idx + 1 + 3; // skip the `---`
1221→        // Include any trailing newline(s) after the closing `---`.
1222→        let after_closing = &raw[closing_end..];
1223→        let body_start = if after_closing.starts_with("\n\n") {
1224→            closing_end + 2
1225→        } else if after_closing.starts_with('\n') {
1226→            closing_end + 1
1227→        } else {
1228→            closing_end
1229→        };
1230→        (&raw[..body_start], &raw[body_start..])
1231→    } else {
1232→        ("", raw)
1233→    }
1234→}
1235→
1236→/// Replace the `description: ...` line in a frontmatter block.
1237→///
1238→/// The value is YAML-quoted to prevent indicator characters (`{`, `[`, `>`, `|`,
1239→/// etc.) from being misinterpreted as YAML structure.
1240→fn update_frontmatter_description(frontmatter: &str, new_desc: &str) -> String {
1241→    let mut result = String::with_capacity(frontmatter.len() + new_desc.len());
1242→    let mut found = false;
1243→    for line in frontmatter.lines() {
1244→        if line.starts_with("description:") && !found {
1245→            let quoted = yaml_quote(new_desc);
1246→            result.push_str(&format!("description: {quoted}"));
1247→            found = true;
1248→        } else {
1249→            result.push_str(line);
1250→        }
1251→        result.push('\n');
1252→    }
1253→    // Preserve the blank line between frontmatter and body if the original had one.
1254→    if frontmatter.ends_with("\n\n") && !result.ends_with("\n\n") {
1255→        result.push('\n');
1256→    }
1257→    result
1258→}
1259→
1260→/// Quote a string for safe YAML scalar emission. Plain scalars starting with
1261→/// YAML indicator characters (`{`, `[`, `>`, `|`, `*`, `&`, `!`, `%`, `@`, `` ` ``)
1262→/// or containing `: ` would be misinterpreted. Always double-quoting is safe
1263→/// and avoids edge-case surprises.
1264→fn yaml_quote(s: &str) -> String {
1265→    let escaped = s.replace('\\', "\\\\").replace('"', "\\\"");
1266→    format!("\"{escaped}\"")
1267→}
