1291→fn validate_sidecar_files(files: &[Value]) -> anyhow::Result<Vec<ValidatedSkillFile>> {
1292→    if files.is_empty() {
1293→        return Err(Error::message("at least one file is required").into());
1294→    }
1295→    if files.len() > MAX_SIDECAR_FILES_PER_CALL {
1296→        return Err(Error::message(format!(
1297→            "too many files: maximum is {MAX_SIDECAR_FILES_PER_CALL}"
1298→        ))
1299→        .into());
1300→    }
1301→
1302→    let mut total_bytes = 0usize;
1303→    let mut seen_paths = HashSet::new();
1304→    let mut validated = Vec::with_capacity(files.len());
1305→
1306→    for file in files {
1307→        let path = file
1308→            .get("path")
1309→            .and_then(|v| v.as_str())
1310→            .ok_or_else(|| Error::message("each file needs a string 'path'"))?;
1311→        let content = file
1312→            .get("content")
1313→            .and_then(|v| v.as_str())
1314→            .ok_or_else(|| Error::message("each file needs a string 'content'"))?;
1315→
1316→        let relative_path = normalize_relative_skill_file_path(path)?;
1317→        if !seen_paths.insert(relative_path.clone()) {
1318→            return Err(Error::message(format!(
1319→                "duplicate file path '{}'",
1320→                relative_path.display()
1321→            ))
1322→            .into());
1323→        }
1324→
1325→        let file_bytes = content.len();
1326→        if file_bytes > MAX_SIDECAR_FILE_BYTES {
1327→            return Err(Error::message(format!(
1328→                "file '{}' exceeds maximum size of {MAX_SIDECAR_FILE_BYTES} bytes",
1329→                relative_path.display()
1330→            ))
1331→            .into());
1332→        }
1333→
1334→        total_bytes += file_bytes;
1335→        if total_bytes > MAX_SIDECAR_TOTAL_BYTES {
1336→            return Err(Error::message(format!(
1337→                "total file content exceeds maximum size of {MAX_SIDECAR_TOTAL_BYTES} bytes"
1338→            ))
1339→            .into());
1340→        }
1341→
1342→        validated.push(ValidatedSkillFile {
1343→            relative_path,
1344→            content: content.to_string(),
1345→        });
1346→    }
1347→
1348→    Ok(validated)
1349→}
