1351→fn normalize_relative_skill_file_path(path: &str) -> anyhow::Result<PathBuf> {
1352→    let trimmed = path.trim();
1353→    if trimmed.is_empty() {
1354→        return Err(Error::message("file path must not be empty").into());
1355→    }
1356→
1357→    let candidate = Path::new(trimmed);
1358→    if candidate.is_absolute() {
1359→        return Err(Error::message("file path must be relative").into());
1360→    }
1361→
1362→    let mut normalized = PathBuf::new();
1363→    for component in candidate.components() {
1364→        match component {
1365→            Component::Normal(segment) => {
1366→                let Some(segment_str) = segment.to_str() else {
1367→                    return Err(Error::message("file path must be valid UTF-8").into());
1368→                };
1369→                if segment_str.starts_with('.') {
1370→                    return Err(Error::message(format!(
1371→                        "hidden path components are not allowed: '{trimmed}'"
1372→                    ))
1373→                    .into());
1374→                }
1375→                normalized.push(segment);
1376→            },
1377→            Component::CurDir => {},
1378→            Component::ParentDir | Component::RootDir | Component::Prefix(_) => {
1379→                return Err(Error::message("path traversal is not allowed").into());
1380→            },
1381→        }
1382→    }
1383→
1384→    let Some(file_name) = normalized.file_name().and_then(|name| name.to_str()) else {
1385→        return Err(Error::message("file path must name a file").into());
1386→    };
1387→
1388→    if file_name.eq_ignore_ascii_case("SKILL.md") {
1389→        return Err(
1390→            Error::message("SKILL.md must be managed with create_skill/update_skill").into(),
1391→        );
1392→    }
1393→
1394→    Ok(normalized)
1395→}
1396→
1397→async fn write_sidecar_files(skill_dir: &Path, files: &[ValidatedSkillFile]) -> crate::Result<()> {
1398→    // Anchor the confinement check to the canonical *skills root*, not the
1399→    // skill directory itself.  If `<data_dir>/skills/<name>` were a symlink
1400→    // pointing outside the tree, using `canonicalize(skill_dir)` as the base
1401→    // would silently accept writes to the symlink target.
1402→    let skills_root = skill_dir
1403→        .parent()
1404→        .ok_or_else(|| Error::message("invalid skill directory"))?;
1405→    let canonical_skills_root = tokio::fs::canonicalize(skills_root).await?;
1406→
1407→    // Reject a skill directory that is itself a symlink.
1408→    let skill_meta = tokio::fs::symlink_metadata(skill_dir).await?;
1409→    if skill_meta.file_type().is_symlink() {
1410→        return Err(Error::message("skill directory must not be a symlink"));
1411→    }
1412→
1413→    let canonical_base = tokio::fs::canonicalize(skill_dir).await?;
1414→    if !canonical_base.starts_with(&canonical_skills_root) {
1415→        return Err(Error::message("skill directory is outside the skills root"));
1416→    }
1417→
1418→    let mut written_paths: Vec<PathBuf> = Vec::new();
1419→
1420→    for file in files {
1421→        let target = skill_dir.join(&file.relative_path);
1422→        let parent = target
1423→            .parent()
1424→            .ok_or_else(|| Error::message("invalid file path"))?;
1425→
1426→        // Validate path ancestry *before* creating directories so a symlinked
1427→        // intermediate cannot cause out-of-tree directory creation.
1428→        validate_no_symlinks_in_ancestry(skill_dir, &file.relative_path).await?;
1429→
1430→        tokio::fs::create_dir_all(parent).await?;
1431→
1432→        let canonical_parent = tokio::fs::canonicalize(parent).await?;
1433→        if !canonical_parent.starts_with(&canonical_base) {
1434→            rollback_written_files(&written_paths).await;
1435→            return Err(Error::message(
1436→                "can only write inside the personal skill directory",
1437→            ));
1438→        }
1439→
1440→        if let Ok(metadata) = tokio::fs::symlink_metadata(&target).await {
1441→            if metadata.file_type().is_symlink() {
1442→                rollback_written_files(&written_paths).await;
1443→                return Err(Error::message(format!(
1444→                    "refusing to write through symlink '{}'",
1445→                    file.relative_path.display()
1446→                )));
1447→            }
1448→            if metadata.is_dir() {
1449→                rollback_written_files(&written_paths).await;
1450→                return Err(Error::message(format!(
1451→                    "target '{}' is a directory",
1452→                    file.relative_path.display()
1453→                )));
1454→            }
1455→        }
1456→
1457→        let Some(file_name) = file
1458→            .relative_path
1459→            .file_name()
1460→            .and_then(|value| value.to_str())
1461→        else {
1462→            rollback_written_files(&written_paths).await;
1463→            return Err(Error::message("invalid file name"));
1464→        };
1465→        let temp_name = format!(".{file_name}.moltis-tmp-{}", uuid::Uuid::new_v4());
1466→        let temp_path = parent.join(temp_name);
1467→
1468→        tokio::fs::write(&temp_path, &file.content).await?;
1469→        if let Err(error) = tokio::fs::rename(&temp_path, &target).await {
1470→            let _ = tokio::fs::remove_file(&temp_path).await;
1471→            rollback_written_files(&written_paths).await;
1472→            return Err(error.into());
1473→        }
1474→        written_paths.push(target);
1475→    }
1476→
1477→    Ok(())
1478→}
1479→
1480→/// Walk from `base` through the existing intermediate components of
1481→/// `relative_path` (excluding the final file component) and reject any
1482→/// symlink.  This prevents `create_dir_all` from following a symlinked
1483→/// intermediate and creating directories outside the skill tree.
1484→async fn validate_no_symlinks_in_ancestry(base: &Path, relative_path: &Path) -> crate::Result<()> {
1485→    let components: Vec<_> = relative_path.components().collect();
1486→    // Only check parent components — the last component is the file itself.
1487→    let parent_components = components.len().saturating_sub(1);
1488→    let mut current = base.to_path_buf();
1489→    for component in components.iter().take(parent_components) {
1490→        if let Component::Normal(segment) = component {
1491→            current.push(segment);
1492→            match tokio::fs::symlink_metadata(&current).await {
1493→                Ok(meta) if meta.file_type().is_symlink() => {
1494→                    return Err(Error::message(format!(
1495→                        "refusing to traverse symlink at '{}'",
1496→                        current.display()
1497→                    )));
1498→                },
1499→                Ok(_) => {},
1500→                // Path doesn't exist yet — safe to stop; create_dir_all will
1501→                // create it as a real directory.
1502→                Err(_) => break,
1503→            }
1504→        }
1505→    }
1506→    Ok(())
1507→}
1508→
1509→/// Best-effort removal of already-written files when a batch fails mid-way.
1510→async fn rollback_written_files(paths: &[PathBuf]) {
1511→    for path in paths.iter().rev() {
1512→        let _ = tokio::fs::remove_file(path).await;
1513→    }
1514→}
