1516→fn audit_sidecar_file_write(data_dir: &Path, skill_name: &str, files: &[ValidatedSkillFile]) {
1517→    let dir = data_dir.join("logs");
1518→    let path = dir.join("security-audit.jsonl");
1519→    let now_ms = std::time::SystemTime::now()
1520→        .duration_since(std::time::UNIX_EPOCH)
1521→        .unwrap_or_default()
1522→        .as_millis() as u64;
1523→    let line = serde_json::json!({
1524→        "ts": now_ms,
1525→        "event": "skills.sidecar_files.write",
1526→        "details": {
1527→            "skill": skill_name,
1528→            "files": files.iter().map(|file| {
1529→                serde_json::json!({
1530→                    "path": file.relative_path.display().to_string(),
1531→                    "bytes": file.content.len(),
1532→                })
1533→            }).collect::<Vec<_>>(),
1534→        },
1535→    })
1536→    .to_string();
1537→
1538→    if let Err(err) = (|| -> std::io::Result<()> {
1539→        std::fs::create_dir_all(&dir)?;
1540→        let mut file = std::fs::OpenOptions::new()
1541→            .create(true)
1542→            .append(true)
1543→            .open(path)?;
1544→        use std::io::Write as _;
1545→        writeln!(file, "{line}")?;
1546→        Ok(())
1547→    })() {
1548→        tracing::warn!(
1549→            error = %err,
1550→            skill = skill_name,
1551→            "failed to write sidecar-file audit entry"
1552→        );
1553→    }
1554→}
