770→/// Sidecar subdirectories that are walked for the primary-read linked-files
771→/// listing. Re-exported from [`moltis_skills::SIDECAR_SUBDIRS`] so the prompt
772→/// generator and the read-side walker stay in lockstep — adding a new entry
773→/// in the skills crate automatically propagates to both the activation
774→/// instruction and this walker, eliminating a whole class of drift bugs.
775→const SIDECAR_SUBDIRS: &[&str] = moltis_skills::SIDECAR_SUBDIRS;
776→
777→/// Entry returned by [`list_skill_sidecar_files`]. Sorted-for-determinism and
778→/// kept as a typed struct so both the primary read path and the sidecar
779→/// "file not found" error path can reuse it.
780→#[derive(Debug, Clone)]
781→struct SidecarEntry {
782→    /// Path relative to the skill directory, e.g. `references/api.md`.
783→    relative_path: String,
784→    bytes: u64,
785→}
786→
787→impl From<&SidecarEntry> for Value {
788→    fn from(entry: &SidecarEntry) -> Self {
789→        json!({
790→            "path": entry.relative_path,
791→            "bytes": entry.bytes,
792→        })
793→    }
794→}
795→
796→/// One-level-deep walk of `<skill_dir>/{references,templates,assets,scripts}`.
797→///
798→/// Returns a sorted (by relative path) list of entries, capped at
799→/// [`MAX_SIDECAR_FILES_PER_CALL`]. Directory entries, symlinks, hidden files
800→/// (dotfiles), and unreadable entries are skipped silently so the listing
801→/// only shows real in-skill files the agent can actually consume.
802→async fn list_skill_sidecar_files(skill_dir: &Path) -> crate::Result<Vec<Value>> {
803→    let mut entries = collect_sidecar_entries(skill_dir).await?;
804→    // Sort for deterministic output — makes tests stable and the agent's
805→    // reasoning traces reproducible across runs.
806→    entries.sort_by(|a, b| a.relative_path.cmp(&b.relative_path));
807→    Ok(entries.iter().map(Value::from).collect())
808→}
809→
810→async fn collect_sidecar_entries(skill_dir: &Path) -> crate::Result<Vec<SidecarEntry>> {
811→    let mut out: Vec<SidecarEntry> = Vec::new();
812→
813→    for sub in SIDECAR_SUBDIRS {
814→        // Stop early if the global cap is already exhausted so we don't
815→        // over-report, but *do* enter each subdir as long as it has free
816→        // budget — the per-subdir cap below guarantees every populated
817→        // subdirectory gets its fair share even when one dir contains
818→        // hundreds of files.
819→        if out.len() >= MAX_SIDECAR_FILES_PER_CALL {
820→            break;
821→        }
822→        let dir = skill_dir.join(sub);
823→        // Use `tokio::fs::read_dir` directly and treat a missing or
824→        // unreadable subdirectory as "no entries" — avoids a synchronous
825→        // `Path::is_dir()` stat inside this async function.
826→        let mut entries = match tokio::fs::read_dir(&dir).await {
827→            Ok(e) => e,
